DarkRPUI=DarkRPUI or {}; DarkRPUI.Scoreboard=DarkRPUI.Scoreboard or {}
function DarkRPUI.Scoreboard.CreatePlayerRow(parent,ply,cols) local row=vgui.Create("DButton",parent); row:SetTall(64); row:SetText(""); local av=vgui.Create("AvatarImage",row); av:SetSize(40,40); av:SetPos(12,12); av:SetPlayer(ply,40); row.Paint=function(s,w,h) s.Hover=DarkRPUI.UI.HoverLerp(s,12); DarkRPUI.UI.ShadowedBox(14,0,0,w,h,DarkRPUI.LerpColor(s.Hover,DarkRPUI.Color("card"),DarkRPUI.Color("cardHover")),DarkRPUI.Color("border"),65); DarkRPUI.UI.Text(ply:Nick(),"DarkRPUI.Body",66,9); DarkRPUI.UI.Text(ply:SteamID(),"DarkRPUI.Tiny",66,36,DarkRPUI.Color("subtext")); local x=w-10; for i=#cols,1,-1 do local c=DarkRPUI.Scoreboard.Columns[cols[i]]; if c then local val=c.value and c.value(ply) or ""; x=x-(c.width or 80); DarkRPUI.UI.Text(tostring(val),"DarkRPUI.Small",x,22,(c.color and c.color(ply)) or DarkRPUI.Color("text"),c.alignment or TEXT_ALIGN_LEFT) end end end; row.DoRightClick=function() DarkRPUI.Scoreboard.PlayerMenu(ply) end; return row end
